UPDATE words SET example_en_2 = 'Land fragmentation makes large-scale farming difficult.', example_ko_2 = '토지 분절화는 대규모 농업을 어렵게 만들어요.', example_en_3 = 'Urban land fragmentation complicates redevelopment projects.', example_ko_3 = '도시 토지 분절화는 재개발 사업을 복잡하게 만들어요.', example_en_4 = 'Land fragmentation often results from inheritance divisions.', example_ko_4 = '토지 분절화는 상속 분할로 인해 발생하는 경우가 많아요.', example_en_5 = 'Addressing land fragmentation is key to efficient development.', example_ko_5 = '토지 분절화 해소가 효율적인 개발의 핵심이에요.' WHERE id = 'w_home_C2_22';
