UPDATE words SET example_en_2 = 'Equitable title is the right to obtain full ownership.', example_ko_2 = '형평법상 권원은 완전한 소유권을 취득할 권리예요.', example_en_3 = 'She held equitable title while paying off the mortgage.', example_ko_3 = '담보 대출을 갚는 동안 형평법상 권원을 보유했어요.', example_en_4 = 'Equitable title differs from legal title under property law.', example_ko_4 = '형평법상 권원은 재산법상 법적 권원과는 달라요.', example_en_5 = 'Equitable title protects buyers during the purchase process.', example_ko_5 = '형평법상 권원은 구매 과정에서 매수자를 보호해요.' WHERE id = 'w_home_C2_25';
