UPDATE words SET example_en_2 = 'In rem jurisdiction relates to the property''s location, not the owner.', example_ko_2 = '대물 관할권은 소유자가 아닌 부동산 위치와 관련돼요.', example_en_3 = 'The court exercised in rem jurisdiction over the disputed land.', example_ko_3 = '법원이 분쟁 토지에 대해 대물 관할권을 행사했어요.', example_en_4 = 'In rem proceedings can bind all parties with an interest in the property.', example_ko_4 = '대물 소송은 부동산에 이해관계가 있는 모든 당사자를 구속할 수 있어요.', example_en_5 = 'In rem jurisdiction is common in admiralty and property law.', example_ko_5 = '대물 관할권은 해사법과 재산법에서 흔히 볼 수 있어요.' WHERE id = 'w_home_C2_28';
