UPDATE words SET example_en_2 = 'A profit à prendre allows the holder to take resources from another''s land.', example_ko_2 = '수익 지역권은 보유자가 타인의 토지에서 자원을 채취할 수 있게 해요.', example_en_3 = 'The fishing rights were held as a profit à prendre.', example_ko_3 = '어업권이 수익 지역권으로 보유됐어요.', example_en_4 = 'A profit à prendre must be registered to bind future owners.', example_ko_4 = '수익 지역권은 미래 소유자를 구속하기 위해 등기해야 해요.', example_en_5 = 'She inherited a profit à prendre granting timber rights.', example_ko_5 = '목재 채취권을 부여하는 수익 지역권을 상속받았어요.' WHERE id = 'w_home_C2_35';
